/* 1. Full-Screen Popup Styles */
.popup-full {
  position: fixed;
  top: 0;
  left: 50%;
  transform: translate(-50%, 100%);
  width: 100%;
  max-width: 480px;
  height: 100%;
  background-color: #ffffff;
  z-index: 1010;
  display: flex;
  flex-direction: column;
  transition: transform 0.4s cubic-bezier(0.36, 0.07, 0.19, 0.97);
}

.popup-full.show {
  transform: translate(-50%, 0);
}

.popup-full-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 16px 20px;
  border-bottom: 1px solid #f1f5f9;
}

.popup-full-content {
  flex: 1;
  overflow-y: auto;
  padding: 24px 20px;
  font-size: 14px;
  line-height: 1.6;
  color: #475569;
}

.popup-full-footer {
  padding: 16px 20px;
  border-top: 1px solid #f1f5f9;
  background-color: #ffffff;
}

.btn-primary-block {
  width: 100%;
  padding: 14px 20px;
  background-color: #6366f1;
  color: #ffffff;
  font-size: 15px;
  font-weight: 700;
  border: none;
  border-radius: 12px;
  cursor: pointer;
}
